const { exec } = require('child_process');
const express = require('express');
const app = express();
app.use(express.json());

app.post('/convert', async (req, res) => {
    const { inputFilename, outputFormat } = req.body;

    if (!inputFilename || !outputFormat) {
        return res.status(400).send('Input filename and output format are required.');
    }

    const allowedFormats = ['pdf', 'docx', 'odt'];
    if (!allowedFormats.includes(outputFormat)) {
        return res.status(400).send(`Unsupported output format: ${outputFormat}`);
    }

    try {
        const outputFilename = `${inputFilename.split('.').slice(0, -1)}.converted.${outputFormat}`;
        await new Promise((resolve, reject) => {
            exec(
                `soffice --headless --convert-to ${outputFormat} "${inputFilename}" --outdir .`,
                (error, stdout, stderr) => {
                    if (error) {
                        return reject(error);
                    }
                    console.log(stdout);
                    resolve();
                }
            );
        });
        res.download(outputFilename, () => {
            // Clean up the temporary file
            exec(`rm "${outputFilename}"`);
        });
    } catch (error) {
        res.status(500).send('Conversion failed.');
    }
});

app.listen(process.env.PORT || 3000, () => {
    console.log('Server is running on port 3000');
});